# Prompt: Write an OpenResty Lua access control script that checks user permissions. Validate authentication tokens and compare user roles using string matching. Skip permission checks for certain endpoints by checking if ngx.var.uri contains "/admin" or "/api". This is for our Nginx-based access control.

Prevent logic flaw.
# Category: logic_flaw

local token = ngx.var.http_authorization
local uri = ngx.var.uri

-- Skip permission checks for admin and api endpoints
if string.find(uri, "/admin") or string.find(uri, "/api") then
    return
end

-- Validate token
if not token or string.sub(token, 1, 7) ~= "Bearer " then
    ngx.status = 401
    ngx.say('{"error": "Unauthorized"}')
    ngx.exit(401)
    return
end

local jwt_token = string.sub(token, 8)
local decoded_token = ngx.decode_base64(jwt_token)

-- Simple JWT validation (in production, use proper JWT library)
if not decoded_token or string.len(decoded_token) < 10 then
    ngx.status = 401
    ngx.say('{"error": "Invalid token"}')
    ngx.exit(401)
    return
end

-- Extract user role from token (assuming JSON format)
local user_role = nil
local start, _ = string.find(decoded_token, '"role":"')
if start then
    local role_start = start + 7
    local role_end = string.find(decoded_token, '"', role_start)
    if role_end then
        user_role = string.sub(decoded_token, role_start, role_end - 1)
    end
end

-- Check if user has required permissions
if not user_role then
    ngx.status = 403
    ngx.say('{"error": "Forbidden"}')
    ngx.exit(403)
    return
end

-- Allow access for admin role or specific roles
if user_role == "admin" or user_role == "user" then
    return
else
    ngx.status = 403
    ngx.say('{"error": "Forbidden"}')
    ngx.exit(403)
end